import{_ as s,C as i,o as a,c as n,ag as l,E as p,j as t,a as e}from"./chunks/framework.DLWhSH9p.js";const b=JSON.parse('{"title":"Proposals","description":"","frontmatter":{},"headers":[],"relativePath":"guide/proposals.md","filePath":"guide/proposals.md"}'),d={name:"guide/proposals.md"};function c(g,o,h,m,u,w){const r=i("SchemeImage");return a(),n("div",null,[o[0]||(o[0]=l('<h1 id="proposals" tabindex="-1">Proposals <a class="header-anchor" href="#proposals" aria-label="Permalink to &quot;Proposals&quot;">​</a></h1><p>Proposals are AI-scored content ideas that go through a curation workflow before entering the production pipeline. Proposals are <strong>channel-scoped</strong> and available to <strong>premium users</strong> only.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><strong>Generation</strong> — the <code>proposal-generate</code> NATS worker analyzes trends, channel history, and audience signals to generate 5 scored proposals per run</li><li><strong>Scoring</strong> — each proposal receives a 0-100 score based on weighted criteria (see below)</li><li><strong>Review</strong> — browse proposals sorted by score, with trend signals and timeliness indicators</li><li><strong>Decision</strong> — approve proposals to convert them into ideas, or reject to dismiss</li></ol><p>Open Proposals from the <strong>channel pill dropdown</strong> → <strong>Proposals</strong> in the top chrome (premium only).</p><h2 id="proposal-fields" tabindex="-1">Proposal Fields <a class="header-anchor" href="#proposal-fields" aria-label="Permalink to &quot;Proposal Fields&quot;">​</a></h2><p>Each generated proposal includes:</p><ul><li><strong>Title</strong> — the proposed video topic</li><li><strong>Hook</strong> — an attention-grabbing opening line</li><li><strong>Angle</strong> — the unique perspective or framing</li><li><strong>Score</strong> — AI confidence score (0-100)</li><li><strong>Reasoning</strong> — why this topic scored the way it did</li><li><strong>Content gap</strong> — what&#39;s missing in existing coverage of this topic</li><li><strong>Suggested angle</strong> — recommended approach for the channel</li><li><strong>Trend signals</strong> — what data points support this topic</li><li><strong>Timeliness</strong> — how time-sensitive the topic is</li><li><strong>Tags</strong> — topic tags for categorization</li></ul><h2 id="scoring-criteria" tabindex="-1">Scoring Criteria <a class="header-anchor" href="#scoring-criteria" aria-label="Permalink to &quot;Scoring Criteria&quot;">​</a></h2><p>The score (0-100) is a weighted composite:</p><table tabindex="0"><thead><tr><th>Factor</th><th>Weight</th><th>Description</th></tr></thead><tbody><tr><td>Trend momentum</td><td>40%</td><td>How strongly the topic is trending right now</td></tr><tr><td>Content gap</td><td>30%</td><td>How underserved the topic is in existing content</td></tr><tr><td>Topic alignment</td><td>20%</td><td>How well the topic fits the channel&#39;s themes</td></tr><tr><td>Timeliness</td><td>10%</td><td>How time-sensitive the opportunity is</td></tr></tbody></table>',11)),p(r,{name:"proposals-panel",alt:"Proposals Panel"}),o[1]||(o[1]=t("div",{class:"tip custom-block"},[t("p",{class:"custom-block-title"},"TIP"),t("p",null,[e("Proposals require the "),t("strong",null,"premium"),e(" role (admin auto-qualifies). See "),t("a",{href:"/guide/auth.html"},"Roles"),e(".")])],-1))])}const P=s(d,[["render",c]]);export{b as __pageData,P as default};
